ME-01:
// who_am_i computes: mystery = a + b
void who_am_i(stat_double &data) {
  data.mystery = data.a + data.b;   // sum of two fields
}

ME-02:
// who_am_i finds maximum of array
data.mystery = data.numbers[0];          // start with first
for (int i = 1; i < 5; i++) {
  if (data.numbers[i] > data.mystery)    // bigger found?
    data.mystery = data.numbers[i];      // update max
}

ME-03:
// who_am_i computes sum of array
data.mystery = 0;                        // start at zero
for (int i = 0; i < 5; i++) {
  data.mystery = data.mystery + data.numbers[i];  // accumulate
}

ME-04:
// who_am_i computes |a - b| (absolute difference)
if (data.a > data.b)
  data.mystery = data.a - data.b;     // a is bigger
else
  data.mystery = data.b - data.a;     // b is bigger

ME-05:
// who_am_i counts how many positives in array
data.mystery = 0;
for (int i = 0; i < 5; i++) {
  if (data.numbers[i] > 0)       // positive check
    data.mystery = data.mystery + 1;  // tally
}
